/**
 * Unified platform event contract — converges Pulse Events and ActivityEvents
 * into one shape Mission Control renders. Write path: normalize → ActivityEvents.
 */

import type { ActivityEvent, ActivityEventInput, ActivityModule } from './activity-events';
import { normalizeActivityEvent } from './activity-events';
import type { AirtableRecord } from './airtable-client';

/** Canonical event shape for attention, agents, and momentum. */
export type PlatformEventSource = 'activity' | 'pulse' | 'agent';

export type PlatformEventCategory =
  | 'attention'
  | 'agent'
  | 'continue'
  | 'momentum'
  | 'activity';

export interface PlatformEvent extends ActivityEvent {
  source: PlatformEventSource;
  category: PlatformEventCategory;
  /** Human-readable explainability for AI recommendations. */
  whyRecommended?: string;
}

/** Loose Pulse Events row shape from ea-payments `pulse-bus`. */
export interface PulseEventRow {
  id?: string;
  organizationId?: string;
  clientSlug?: string;
  clientId?: string;
  eventType?: string;
  type?: string;
  title?: string;
  summary?: string;
  description?: string;
  priority?: number;
  module?: string;
  metric?: string;
  actionLabel?: string;
  actionUrl?: string;
  personId?: string;
  createdAt?: string;
  metadata?: Record<string, unknown> | string;
}

const PULSE_TYPE_IMPORTANCE: Record<string, number> = {
  'assessment.submitted': 70,
  'payment.received': 85,
  'portal.login': 40,
  'apply.submitted': 75,
  'capture.completed': 55,
  'launch.verification.completed': 90,
  'missed follow-up': 100,
};

/** Map a Pulse Events Airtable record to the unified contract. */
export function fromPulseAirtableRecord(record: AirtableRecord): PlatformEvent {
  const fields = record.fields;
  const row: PulseEventRow = {
    id: record.id,
    organizationId: readStr(fields.organizationId) || readStr(fields.Organization) || 'ea',
    clientSlug: readStr(fields.clientSlug) || readStr(fields.ClientSlug),
    eventType: readStr(fields.eventType) || readStr(fields.Type) || readStr(fields.type),
    title: readStr(fields.title) || readStr(fields.Title),
    summary: readStr(fields.summary) || readStr(fields.Summary) || readStr(fields.description),
    priority: readNum(fields.priority) ?? readNum(fields.Priority),
    module: readStr(fields.module) || readStr(fields.Module),
    metric: readStr(fields.metric),
    actionLabel: readStr(fields.actionLabel),
    actionUrl: readStr(fields.actionUrl),
    personId: readStr(fields.personId) || readStr(fields.clientSlug),
    createdAt: readStr(fields.createdAt) || record.createdTime,
    metadata: readMeta(fields.metadata ?? fields.Metadata ?? fields.payload),
  };
  return fromPulseEventRow(row, record.id);
}

export function fromPulseEventRow(row: PulseEventRow, id = ''): PlatformEvent {
  const eventType = (row.eventType ?? row.type ?? 'pulse.event').toLowerCase();
  const module = (row.module ?? inferModuleFromPulseType(eventType)) as ActivityModule;
  const priority = row.priority ?? PULSE_TYPE_IMPORTANCE[eventType] ?? 50;

  const base = normalizeActivityEvent(
    {
      organizationId: row.organizationId ?? 'ea',
      module,
      eventType,
      title: row.title ?? humanizeEventType(eventType),
      summary: row.summary ?? row.description ?? '',
      priority,
      metric: row.metric,
      actionLabel: row.actionLabel,
      actionUrl: row.actionUrl,
      personId: row.personId ?? row.clientSlug ?? row.clientId,
      createdAt: row.createdAt,
      metadata: {
        ...(typeof row.metadata === 'object' ? row.metadata : {}),
        source: 'pulse',
        clientSlug: row.clientSlug,
      },
    },
    id,
  );

  return enrichPlatformEvent(base, 'pulse', inferCategory(base));
}

/** Promote an ActivityEvent to the unified contract (no data loss). */
export function fromActivityEvent(event: ActivityEvent): PlatformEvent {
  const source =
    event.module === 'agent' || event.metadata.agentKind
      ? 'agent'
      : event.metadata.source === 'pulse'
        ? 'pulse'
        : 'activity';
  return enrichPlatformEvent(event, source, inferCategory(event));
}

/** Normalize any platform event for ActivityEvents persistence. */
export function toActivityEventInput(event: PlatformEvent): ActivityEventInput {
  return {
    organizationId: event.organizationId,
    module: event.module,
    eventType: event.eventType,
    title: event.title,
    summary: event.summary,
    priority: event.priority,
    metric: event.metric,
    actionLabel: event.actionLabel,
    actionUrl: event.actionUrl,
    personId: event.personId,
    createdAt: event.createdAt,
    metadata: {
      ...event.metadata,
      source: event.source,
      category: event.category,
      whyRecommended: event.whyRecommended,
    },
  };
}

/** Merge pulse + activity streams, dedupe by id, sort by recency. */
export function mergeEventStreams(
  activity: ActivityEvent[],
  pulse: PlatformEvent[] = [],
): PlatformEvent[] {
  const seen = new Set<string>();
  const merged: PlatformEvent[] = [];

  for (const event of [...pulse, ...activity.map(fromActivityEvent)]) {
    const key = event.id || `${event.eventType}:${event.createdAt}`;
    if (seen.has(key)) continue;
    seen.add(key);
    merged.push(event);
  }

  return merged.sort(
    (a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime(),
  );
}

function enrichPlatformEvent(
  event: ActivityEvent,
  source: PlatformEventSource,
  category: PlatformEventCategory,
): PlatformEvent {
  const why =
    readStr(event.metadata.whyRecommended) ||
    readStr(event.metadata.recommendationReason) ||
    buildDefaultWhy(event);

  return {
    ...event,
    source,
    category,
    whyRecommended: why || undefined,
  };
}

function inferCategory(event: ActivityEvent): PlatformEventCategory {
  if (event.module === 'agent' || event.metadata.agentKind) return 'agent';
  if (event.metadata.continueUrl || event.eventType.toLowerCase().includes('continue')) {
    return 'continue';
  }
  if (event.metadata.momentum) return 'momentum';
  if (event.priority >= 60) return 'attention';
  return 'activity';
}

function inferModuleFromPulseType(eventType: string): string {
  if (eventType.includes('capture')) return 'simplifi';
  if (eventType.includes('apply')) return 'portal';
  if (eventType.includes('payment') || eventType.includes('launch')) return 'pulse';
  if (eventType.includes('assessment')) return 'simplifi';
  return 'pulse';
}

function humanizeEventType(eventType: string): string {
  return eventType
    .split(/[._]/)
    .map((w) => w.charAt(0).toUpperCase() + w.slice(1))
    .join(' ');
}

function buildDefaultWhy(event: ActivityEvent): string | undefined {
  const due = event.metadata.dueDate;
  if (typeof due === 'string') {
    return `Prioritized because the deadline is ${new Date(due).toLocaleDateString()}.`;
  }
  if (event.priority >= 80) {
    return 'Prioritized because this is high-impact work that needs a decision soon.';
  }
  return undefined;
}

function readStr(value: unknown): string {
  return typeof value === 'string' ? value : '';
}

function readNum(value: unknown): number | undefined {
  return typeof value === 'number' && Number.isFinite(value) ? value : undefined;
}

function readMeta(value: unknown): Record<string, unknown> {
  if (!value) return {};
  if (typeof value === 'object' && !Array.isArray(value)) return value as Record<string, unknown>;
  if (typeof value !== 'string') return {};
  try {
    const parsed = JSON.parse(value) as unknown;
    return parsed && typeof parsed === 'object' && !Array.isArray(parsed)
      ? (parsed as Record<string, unknown>)
      : {};
  } catch {
    return {};
  }
}
